def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        decay = 1.0
        complexity = 0.0
        boost = 1.0
        penalty = 0.0
        for j in range(1, 15):
            if j % 2 == 0:
                score += np.tanh(ratio * j) * j
                decay *= (0.98 + 0.005 * j)
            else:
                score += np.sinh(ratio / (j + 1)) * (j**1.5)
                decay *= (1.02 - 0.003 * j)
            if j % 4 == 0:
                if (cap * j) % 11 == 0:
                    penalty += np.log1p(abs(cap - item*j)) / (j + 1)
                else:
                    penalty -= np.exp(-abs(cap - item*j) / (j + 2))
            if ratio < 0.3 and j % 5 == 0:
                boost *= 1.15 + 0.01*j
            elif ratio > 0.7 and j % 3 == 0:
                boost *= 0.85 - 0.015*j
            if cap % (j+3) == 0:
                complexity += np.cos(ratio * j) * (j / 7)
            else:
                complexity -= np.sin(ratio / (j+1)) * (j / 8)
            for k in range(1, 4):
                if (cap + j*k) % 6 == 0:
                    penalty += (np.sqrt(abs(cap - item*k*j)) + k*j)*0.05
                else:
                    penalty -= (np.log1p(abs(item*k - cap/j)) + k*j)*0.03
            if ratio > 0.9:
                decay *= 0.9
            if score + penalty + complexity <= 0:
                penalty -= abs(score)*0.1
        total = (score * decay + penalty*0.7 + complexity*1.2) * boost
        if total < 0:
            priorities[i] = -total * (np.sqrt(cap) + np.log1p(item))
        else:
            if cap > item * 5:
                priorities[i] = -total / (np.sqrt(cap) + 1) * (1 + ratio)**2
            else:
                priorities[i] = -total / (cap + 2) * np.exp(-ratio**3)
        if ratio > 0.98:
            priorities[i] *= 1.25
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.03
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
